A rainbow table attack is a method used to recover the original password from a hash by pre-computing the hash values of all possible passwords and then looking up the hash in a large table (the "rainbow table") to find a match. Here's how you could write code for a basic rainbow table attack in Python:

```python
import hashlib

# Define the hash function and its salt (if applicable)
def hash_password(password, salt=None):
    if salt:
        password += salt
    return hashlib.sha256(password.encode()).hexdigest()

# Function to generate a rainbow table
def generate_rainbow_table(min_length, max_length, charset, num_tables):
    from itertools import product

    def generate_entries(length, charset):
        for password in product(charset, repeat=length):
            yield ''.join(password), hash_password(''.join(password))

    # Generate all possible combinations and their hashes
    entries = list(generate_entries(min_length, charset, num_tables))

    # Create the rainbow table
    rainbow_table = {}
    for index, (password, hash_val) in enumerate(entries):
        rainbow_table[hash_val] = (index, password)

    return rainbow_table

